import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';

const s = {
  page: { padding: 32, maxWidth: 900, margin: '0 auto' },
  title: { fontSize: 26, fontWeight: 700, color: '#1a3a5c', marginBottom: 4 },
  sub: { color: '#888', marginBottom: 28 },
  grid: { display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 18, marginBottom: 32 },
  stat: { background: '#fff', borderRadius: 14, padding: '22px 18px', boxShadow: '0 2px 12px rgba(0,0,0,0.07)', textAlign: 'center' },
  num: { fontSize: 34, fontWeight: 800, marginBottom: 4 },
  label: { fontSize: 12, color: '#888', fontWeight: 600, textTransform: 'uppercase', letterSpacing: 1 },
  actions: { display: 'flex', gap: 16 },
  btn: { padding: '12px 28px', borderRadius: 10, fontWeight: 700, fontSize: 15, cursor: 'pointer', border: 'none', textDecoration: 'none', display: 'inline-block' }
};

export default function AdminDashboard() {
  const [stats, setStats] = useState(null);

  useEffect(() => {
    axios.get('/api/report/summary').then(r => setStats(r.data)).catch(() => {});
  }, []);

  return (
    <div style={s.page}>
      <div style={s.title}>Admin Dashboard 🛡️</div>
      <div style={s.sub}>Manage all bus pass applications and students</div>

      <div style={s.grid}>
        <div style={s.stat}><div style={{ ...s.num, color: '#2980b9' }}>{stats?.total ?? '—'}</div><div style={s.label}>Total</div></div>
        <div style={s.stat}><div style={{ ...s.num, color: '#f39c12' }}>{stats?.pending ?? '—'}</div><div style={s.label}>Pending</div></div>
        <div style={s.stat}><div style={{ ...s.num, color: '#27ae60' }}>{stats?.approved ?? '—'}</div><div style={s.label}>Approved</div></div>
        <div style={s.stat}><div style={{ ...s.num, color: '#e74c3c' }}>{stats?.rejected ?? '—'}</div><div style={s.label}>Rejected</div></div>
      </div>

      <div style={{ ...s.grid, gridTemplateColumns: 'repeat(2,1fr)', marginBottom: 32 }}>
        <div style={s.stat}><div style={{ ...s.num, color: '#8e44ad' }}>{stats?.students ?? '—'}</div><div style={s.label}>Students Registered</div></div>
        <div style={s.stat}><div style={{ ...s.num, color: '#95a5a6' }}>{stats?.expired ?? '—'}</div><div style={s.label}>Expired</div></div>
      </div>

      <div style={s.actions}>
        <Link to="/admin/passes" style={{ ...s.btn, background: '#1a3a5c', color: '#fff' }}>Manage Passes</Link>
        <Link to="/admin/reports" style={{ ...s.btn, background: '#fff', color: '#1a3a5c', border: '2px solid #1a3a5c' }}>View Reports</Link>
      </div>
    </div>
  );
}
